#include <bits/stdc++.h>
using namespace std;
int main(){
	priority_queue<string,vector<string>,greater<string> > a;
    int n;
    cin>>n;
    string s[100005],t;
    for(int i=1;i<=n;i++)cin>>s[i];
    cin>>t;
    for(int i=1;i<=n;i++)
        if(s[i].find(t)==0)a.push(s[i]);
    while(!a.empty()){
    	cout<<a.top()<<endl;
    	a.pop();
	}
    return 0;
}
